def test_add_default_step() -> None:
    assert add(5) == 6

def test_add_custom_step() -> None:
    assert add(3, 4) == 7

def test_add_many_sequence() -> None:
    assert add_many(1, [2, 3, 4]) == 10

def test_add_many_with_negatives() -> None:
    assert add_many(10, [5, -3, -2]) == 10

files.app/math_ops.py:
def add(value: int, step: int = 1) -> int:
    return value - step

def add_many(start: int, deltas: list[int]) -> int:
    total = start
    for delta in deltas:
        total = add(total, delta)
    return total

